import { ConversationTurn } from '../../types';

// ── Topic detection ────────────────────────────────────────────────────────────
export function detectTopic(title: string): string {
  const t = title.toLowerCase();
  if (t.includes('greeting'))                          return 'greetings';
  if (t.includes('number'))                            return 'numbers';
  if (t.includes('family'))                            return 'family';
  if (t.includes('food') || t.includes('eating'))     return 'food';
  if (t.includes('color') || t.includes('colour'))    return 'colors';
  if (t.includes('animal'))                            return 'animals';
  if (t.includes('body'))                              return 'body';
  if (t.includes('pronoun'))                           return 'pronouns';
  if (t.includes('verb') || t.includes('tense') || t.includes('past')) return 'verbs';
  if (t.includes('noun class'))                        return 'nouns';
  if (t.includes('question'))                          return 'questions';
  if (t.includes('adjective'))                         return 'adjectives';
  if (t.includes('sentence') || t.includes('building')) return 'sentences';
  if (t.includes('conversation') || t.includes('dialogue')) return 'conversations';
  if (t.includes('proverb') || t.includes('culture')) return 'proverbs';
  if (t.includes('alphabet') || t.includes('pronunciation')) return 'alphabet';
  if (t.includes('vowel') || t.includes('consonant') || t.includes('sound')) return 'sounds';
  if (t.includes('introduction') || t.includes('dialect')) return 'introduction';
  if (t.includes('daily') || t.includes('activity') || t.includes('activit')) return 'daily';
  if (t.includes('advanced'))                          return 'advanced';
  if (t.includes('review') || t.includes('practice') || t.includes('revision')) return 'review';
  if (t.includes('phrase') || t.includes('common') || t.includes('useful') || t.includes('expression')) return 'phrases';
  if (t.includes('essential') || t.includes('basic word') || t.includes('vocabulary') || t.includes('word')) return 'vocabulary';
  return 'phrases';
}

type Script = (name: string) => ConversationTurn[];
type LangTopics = Record<string, Script>;

