// Master map + export
// ─────────────────────────────────────────────────────────────────────────────
const SCRIPTS: Record<string, LangTopics> = {
  swahili, hausa, yoruba, igbo, zulu, amharic, arabic, shona, somali, berber, moore, lingala, twi, chichewa, wolof,
};

const fallbackScript: Script = (name) => [
  { speaker:'guide', text:`Hello, ${name}!`, textTranslation:`Hello, ${name}!`, textTranslationFr:`Bonjour, ${name} !` },
  { speaker:'user', text:'Hello!', textTranslation:'Hello! (greeting back)', textTranslationFr:'Bonjour !',
    options:['Hello!','Goodbye!','Thank you!'], correctIndex:0,
    wrongExplanation:'"Hello!" is the correct greeting reply.',
    wrongExplanationFr:'"Hello !" est la bonne réponse.' },
  { speaker:'guide', text:'How are you today?', textTranslation:'How are you today?', textTranslationFr:'Comment allez-vous ?' },
  { speaker:'user', text:"I'm fine, thank you!", textTranslation:"I'm fine, thank you!", textTranslationFr:'Je vais bien, merci !',
    options:["I'm fine, thank you!",'I don\'t know.','Goodbye!'], correctIndex:0,
    wrongExplanation:'"I\'m fine, thank you!" is the polite standard reply.',
    wrongExplanationFr:'"Je vais bien, merci !" est la réponse polie.' },
  { speaker:'guide', text:'Wonderful! Let\'s start our lesson!', textTranslation:'Wonderful! Let\'s start our lesson!', textTranslationFr:'Merveilleux ! Commençons notre leçon !' },
];

/**
 * Returns a 5-7 turn conversation script for the given language and lesson topic.
 * The guide's opening line is personalised with the user's name.
 */
export function getConversationScript(
  languageId: string,
  userName: string,
  lessonTitle = '',
): ConversationTurn[] {
  const topic = detectTopic(lessonTitle);
  const langScripts = SCRIPTS[languageId];
  if (!langScripts) return fallbackScript(userName);
  const fn = langScripts[topic] ?? langScripts['greetings'] ?? fallbackScript;
  return fn(userName);
}
